      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      var d1 = f.getItem('ngay_tu').value, d2 = f.getItem('ngay_den').value, x = f.getItemValue('mau_bc'), q = f.getItemValue('chon_tt');
      g._ValueFormType = x;
      g._hiddenFields = [
        {Fields: 'kh_nam_nt, tien_nt, lk_dn_nt, lk_kc_nt', Value: (x == '10')},
        {Fields: 'kh_nam, tien, lk_dn, lk_kc', Value: (x == '20')},
        {Fields: 'chi_tieu', Value: (g._language == 'e')},
        {Fields: 'chi_tieu2', Value: (g._language == 'v')}
      ];
      g._hiddenForms = [
        {Form: [0, 1, 5, 6], Value: (q == '2')},
        {Form: [2, 3, 7, 8], Value: (q != '2')}
      ];
      x = f.getItem('form').selectedIndex, y = f.getItem('form').options;
      var formName = y[x].text;
      g._alterTitle = [null, [['%f1', formName, true], ['%d1', d1, true], ['%d2', d2, true]]];
      g._queryFilterString = getQueryFilterString(f, 'ngay_tu, ngay_den, ma_vv, nhom_1, nhom_2, nhom_3, ma_dvcs, form, mau_bc');
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255));
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
  }
  if (value.length > 1) o.options[1].selected = true;
}
